export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    // Route table: map external paths to internal services.
    // Bindings expected in wrangler.toml under [services] for each name.
    const routes = [
      { prefix: "/api/users", service: "USERS" },
      { prefix: "/api/orders", service: "ORDERS" },
      { prefix: "/api/compute", service: "COMPUTE" },
      { prefix: "/api/health", service: "HEALTH" },
    ];

    const match = routes
      .slice()
      .sort((a, b) => b.prefix.length - a.prefix.length)
      .find((r) => url.pathname === r.prefix || url.pathname.startsWith(r.prefix + "/"));

    if (!match) {
      return new Response(
        JSON.stringify({
          error: "not_found",
          message: "No route matches this request",
          path: url.pathname,
        }),
        { status: 404, headers: { "content-type": "application/json; charset=utf-8" } }
      );
    }

    const target = env[match.service];
    if (!target || typeof target.fetch !== "function") {
      return new Response(
        JSON.stringify({
          error: "misconfigured_service_binding",
          message: `Missing service binding: ${match.service}`,
        }),
        { status: 500, headers: { "content-type": "application/json; charset=utf-8" } }
      );
    }

    // Preserve original request; internal services can re-route based on URL.
    // Forward additional headers for traceability.
    const forwardedHeaders = new Headers(request.headers);
    forwardedHeaders.set("x-edge-gateway", "public-worker");
    forwardedHeaders.set("x-edge-request-id", crypto.randomUUID());
    forwardedHeaders.set("x-forwarded-host", url.host);
    forwardedHeaders.set("x-forwarded-proto", url.protocol.replace(":", ""));

    // Use the same URL to allow internal worker routing by pathname.
    const internalRequest = new Request(url.toString(), {
      method: request.method,
      headers: forwardedHeaders,
      body: request.body,
      redirect: "manual",
      cf: request.cf,
    });

    // Attach a stable timeout guard if desired; internal service should be fast.
    const controller = new AbortController();
    const timeoutMs = 25000;
    const t = setTimeout(() => controller.abort("gateway_timeout"), timeoutMs);
    let res;
    try {
      res = await target.fetch(internalRequest, { signal: controller.signal });
    } catch (err) {
      clearTimeout(t);
      const msg = err && typeof err === "object" && "message" in err ? err.message : String(err);
      return new Response(
        JSON.stringify({ error: "upstream_error", message: msg, service: match.service }),
        { status: 502, headers: { "content-type": "application/json; charset=utf-8" } }
      );
    }
    clearTimeout(t);

    // Add gateway header; keep body/headers/status as-is.
    const outHeaders = new Headers(res.headers);
    outHeaders.set("x-edge-gateway", "public-worker");
    outHeaders.set("x-edge-upstream", match.service);

    return new Response(res.body, {
      status: res.status,
      statusText: res.statusText,
      headers: outHeaders,
    });
  },
};


