async function safeJson(resOrReq) {
  try {
    const ct = resOrReq.headers?.get?.("content-type") || "";
    if (ct.includes("application/json")) return await resOrReq.json();
    const text = await resOrReq.text();
    try {
      return JSON.parse(text);
    } catch {
      return { raw: text };
    }
  } catch (e) {
    return { error: "invalid_json", message: String(e) };
  }
}

function passthroughHeaders(request, extra = {}) {
  const h = new Headers();
  const allow = [
    "authorization",
    "cookie",
    "x-edge-request-id",
    "x-forwarded-host",
    "x-forwarded-proto",
    "cf-connecting-ip",
    "user-agent",
    "accept",
    "content-type",
  ];
  for (const k of allow) {
    const v = request.headers.get(k);
    if (v) h.set(k, v);
  }
  for (const [k, v] of Object.entries(extra)) h.set(k, v);
  return h;
}


