export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === "/api/health" && request.method === "GET") {
      // Optionally fan-out checks to other services if bound.
      const checks = {};
      await Promise.all(
        ["USERS", "ORDERS", "COMPUTE"].map(async (name) => {
          const svc = env[name];
          if (!svc || typeof svc.fetch !== "function") {
            checks[name] = { ok: false, error: "missing_binding" };
            return;
          }
          try {
            const res = await svc.fetch(new Request(new URL("/internal/health", url).toString(), { method: "GET" }));
            checks[name] = { ok: res.ok, status: res.status };
          } catch (e) {
            checks[name] = { ok: false, error: String(e) };
          }
        })
      );

      return json({
        service: "health",
        ok: true,
        checks,
        ts: new Date().toISOString(),
      });
    }

    if (path === "/internal/health" && request.method === "GET") {
      return json({ ok: true, service: "health", ts: Date.now() });
    }

    return json({ error: "not_found", service: "health", path, method: request.method }, 404);
  },
};

